#include <bits/stdc++.h>
using namespace std;

int main() {
    string s;
    getline(cin, s);
    vector<string> parts;
    stringstream ss(s);
    string item;
    while (getline(ss, item, ',')) {
        parts.push_back(item);
    }
    if (parts.size() < 3) return 0;
    string S = parts[0], S1 = parts[1], S2 = parts[2];
    size_t pos1 = S.find(S1);
    size_t pos2 = S.rfind(S2);
    if (pos1 == string::npos || pos2 == string::npos || pos1 + S1.length() > pos2) {
        cout << -1 << endl;
    } else {
        int distance = pos2 - (pos1 + S1.length());
        cout << distance << endl;
    }
    return 0;
}
